// TIER 2: Parse Claude response and extract email content
const claudeResponse = $input.first().json;
const prospectData = $('Extract Webhook Data').first().json;

// Extract content from Claude response
let emailData;
try {
  const content = claudeResponse.content[0].text;
  emailData = JSON.parse(content);
} catch (e) {
  // Fallback parsing if JSON is wrapped in markdown
  const content = claudeResponse.content[0].text;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    emailData = JSON.parse(jsonMatch[0]);
  } else {
    throw new Error('Failed to parse Claude response: ' + content);
  }
}

// Combine with prospect data
return [{
  json: {
    // Prospect info
    company_id: prospectData.company_id,
    company_name: prospectData.company_name,
    decision_maker_name: prospectData.decision_maker_name,
    decision_maker_email: prospectData.decision_maker_email,

    // Generated email content
    email_body: emailData.email_body,
    subject_line_1: emailData.subject_line_1,
    subject_line_2: emailData.subject_line_2,
    subject_line_3: emailData.subject_line_3,
    personalization_notes: emailData.personalization_notes,

    // Metadata
    generated_at: new Date().toISOString(),
    generated_by: 'tier2_claude_email_gen',
    status: 'draft',
    approved: false
  }
}];

// TIER 2: Parse quality check results
const qualityResponse = $input.first().json;
const emailData = $('Parse Email Content').first().json;

let qualityCheck;
try {
  const content = qualityResponse.content[0].text;
  qualityCheck = JSON.parse(content);
} catch (e) {
  const content = qualityResponse.content[0].text;
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    qualityCheck = JSON.parse(jsonMatch[0]);
  } else {
    // Default to safe values if parsing fails
    qualityCheck = {
      quality_score: 5,
      issues: ['Quality check parsing failed'],
      suggestions: [],
      spam_risk: 'medium',
      approved_for_send: false
    };
  }
}

return [{
  json: {
    ...emailData,
    quality_score: qualityCheck.quality_score,
    quality_issues: qualityCheck.issues?.join('; ') || 'none',
    quality_suggestions: qualityCheck.suggestions?.join('; ') || 'none',
    spam_risk: qualityCheck.spam_risk,
    approved_for_send: qualityCheck.approved_for_send && qualityCheck.quality_score >= 7,
    quality_checked_at: new Date().toISOString()
  }
}];

// TIER 2: Generate response for webhook caller
const emailData = $input.first().json;

const response = {
  success: true,
  company_id: emailData.company_id,
  company_name: emailData.company_name,
  email_generated: true,
  quality_score: emailData.quality_score,
  approved_for_send: emailData.approved_for_send,
  status: emailData.approved_for_send ? 'queued_for_send' : 'needs_review',
  generated_at: emailData.generated_at,
  subject_variants: [
    emailData.subject_line_1,
    emailData.subject_line_2,
    emailData.subject_line_3
  ]
};

return [{ json: response }];
